function solve(n, k) {
    if (k === 0) {
        return n >= 1 ? 1 : 0;
    }

    const memo = new Map();
    const maxBits = Math.floor(Math.log2(n)) + 1;

    function countNumbersWithPopcount(bits, ones, isTight) {
        if (bits === 0) {
            return ones === 0 ? 1 : 0;
        }
        const key = `${bits},${ones},${isTight}`;
        if (memo.has(key)) {
            return memo.get(key);
        }

        let limit = isTight ? (n >> (bits - 1)) & 1 : 1;
        let total = 0;

        for (let d = 0; d <= limit; d++) {
            const newIsTight = isTight && (d === limit);
            const newOnes = ones - (d === 1 ? 1 : 0);
            if (newOnes >= 0) {
                total += countNumbersWithPopcount(bits - 1, newOnes, newIsTight);
            }
        }

        memo.set(key, total);
        return total;
    }

    function getPopcountDepth(x) {
        let depth = 0;
        while (x !== 1) {
            x = x.toString(2).split('0').join('').length;
            depth++;
        }
        return depth;
    }

    let result = 0;
    for (let x = 1; x <= n; x++) {
        if (getPopcountDepth(x) === k) {
            result++;
        }
        if (x > 1000000) {
            // For large n, switch to DP approach
            break;
        }
    }

    if (result === 0 || n <= 1000000) {
        return result;
    }

    // For large n, use DP to count numbers with popcount-depth k
    result = 0;
    for (let targetOnes = 1; targetOnes <= maxBits; targetOnes++) {
        const cnt = countNumbersWithPopcount(maxBits, targetOnes, true);
        let depth = 0;
        let current = targetOnes;
        while (current !== 1) {
            current = current.toString(2).split('0').join('').length;
            depth++;
        }
        if (depth === k - 1) {
            result += cnt;
        }
    }
    return result;
}

