use std::collections::HashMap;

fn solve(n: i64, k: i64) -> i64 {
    if k == 0 {
        return if n >= 1 { 1 } else { 0 };
    }

    let max_bits = (n as f64).log2().floor() as i64 + 1;
    let mut memo = HashMap::new();

    fn count_numbers_with_popcount(
        bits: i64,
        ones: i64,
        is_tight: bool,
        n: i64,
        memo: &mut HashMap<(i64, i64, bool), i64>,
    ) -> i64 {
        if bits == 0 {
            return if ones == 0 { 1 } else { 0 };
        }
        let key = (bits, ones, is_tight);
        if let Some(&val) = memo.get(&key) {
            return val;
        }

        let limit = if is_tight { (n >> (bits - 1)) & 1 } else { 1 };
        let mut total = 0;

        for d in 0..=limit {
            let new_is_tight = is_tight && (d == limit);
            let new_ones = ones - if d == 1 { 1 } else { 0 };
            if new_ones >= 0 {
                total += count_numbers_with_popcount(bits - 1, new_ones, new_is_tight, n, memo);
            }
        }

        memo.insert(key, total);
        total
    }

    fn get_popcount_depth(mut x: i64) -> i64 {
        let mut depth = 0;
        while x != 1 {
            x = x.count_ones() as i64;
            depth += 1;
        }
        depth
    }

    if n <= 1_000_000 {
        let mut result = 0;
        for x in 1..=n {
            if get_popcount_depth(x) == k {
                result += 1;
            }
        }
        return result;
    }

    let mut result = 0;
    for target_ones in 1..=max_bits {
        let cnt = count_numbers_with_popcount(max_bits, target_ones, true, n, &mut memo);
        let mut depth = 0;
        let mut current = target_ones;
        while current != 1 {
            current = current.count_ones() as i64;
            depth += 1;
        }
        if depth == k - 1 {
            result += cnt;
        }
    }
    result
}
