fn solve(n: i64, k: i64) -> i64 {
    if k == 0 {
        return if n >= 1 { 1 } else { 0 };
    }

    fn popcount(mut x: i64) -> i64 {
        let mut count = 0;
        while x > 0 {
            count += x & 1;
            x >>= 1;
        }
        count
    }

    fn get_depth(mut x: i64) -> i64 {
        let mut depth = 0;
        while x != 1 {
            x = popcount(x);
            depth += 1;
        }
        depth
    }

    let max_bits = 60; // Since n can be up to 1e15, 60 bits are sufficient
    let mut dp = vec![vec![vec![-1; 2]; 60]; 60];

    fn dfs(
        pos: usize,
        ones: i64,
        tight: bool,
        bits: &[i64],
        dp: &mut Vec<Vec<Vec<i64>>>,
    ) -> i64 {
        if pos == bits.len() {
            return if ones == 0 { 1 } else { 0 };
        }
        let tight_idx = tight as usize;
        if dp[pos][ones as usize][tight_idx] != -1 {
            return dp[pos][ones as usize][tight_idx];
        }
        let limit = if tight { bits[pos] } else { 1 };
        let mut total = 0;
        for d in 0..=limit {
            let new_tight = tight && (d == bits[pos]);
            let new_ones = ones - (d == 1) as i64;
            if new_ones >= 0 {
                total += dfs(pos + 1, new_ones, new_tight, bits, dp);
            }
        }
        dp[pos][ones as usize][tight_idx] = total;
        total
    }

    let bits: Vec<i64> = (0..max_bits)
        .rev()
        .map(|i| (n >> i) & 1)
        .collect();

    let mut result = 0;
    for target_ones in 1..=max_bits as i64 {
        dp.iter_mut().for_each(|v| v.iter_mut().for_each(|u| u.fill(-1)));
        let cnt = dfs(0, target_ones, true, &bits, &mut dp);
        let mut depth = 0;
        let mut current = target_ones;
        while current != 1 {
            current = popcount(current);
            depth += 1;
        }
        if depth == k - 1 {
            result += cnt;
        }
    }
    result
}
